// Pre-hook: verifica env vars (pattern repo)
const startedAt = new Date().toISOString();
const missingVars = [];
if (!$env.TELEGRAM_BOT_TOKEN) missingVars.push('TELEGRAM_BOT_TOKEN');
if (!$env.TELEGRAM_CHAT_ID) missingVars.push('TELEGRAM_CHAT_ID');
if (!$env.DASHBOARD_API_KEY) missingVars.push('DASHBOARD_API_KEY');
if (!$env.ANTHROPIC_API_KEY) missingVars.push('ANTHROPIC_API_KEY');
if (missingVars.length > 0) {
  throw new Error('Pre-hook FAIL — env vars mancanti: ' + missingVars.join(', '));
}
return [{ json: { startedAt, workflow: 'linkedin-detection-sentinel', ok: true } }];

// Fonti RSS/Atom verificate VIVE 2026-06-11 (goal detection-news, wf_c13bbb76-897).
// NB Reddit: usare .rss — le varianti .json rispondono 403 a richieste non autenticate (verificato giu 2026).
const feeds = [
  { source: 'expandi', url: 'https://expandi.io/feed/' },
  { source: 'phantombuster', url: 'https://phantombuster.com/blog/feed/' },
  { source: 'dux-soup', url: 'https://www.dux-soup.com/blog/rss.xml' },
  { source: 'dripify', url: 'https://dripify.com/feed/' },
  { source: 'reddit-banwave-radar', url: 'https://www.reddit.com/search.rss?q=linkedin+%28restricted+OR+banned+OR+%22ban+wave%22+OR+%22account+restricted%22+OR+%22automation+detected%22%29&sort=new&t=week&limit=25' },
  { source: 'reddit-r-linkedin', url: 'https://www.reddit.com/r/linkedin/search.rss?q=restricted+OR+banned+OR+%22ban+wave%22+OR+automation+OR+detected&restrict_sr=1&sort=new&limit=25' },
  { source: 'stackoverflow-linkedin-api', url: 'https://stackoverflow.com/feeds/tag?tagnames=linkedin-api&sort=newest' },
  { source: 'patchright-releases', url: 'https://github.com/Kaliiiiiiiiii-Vinyzu/patchright/releases.atom' },
  { source: 'phantombuster-status', url: 'https://status.phantombuster.com/history.rss' },
  { source: 'google-news-detection', url: 'https://news.google.com/rss/search?q=LinkedIn+(scraping+OR+lawsuit+OR+%22account+restricted%22+OR+%22mass+ban%22+OR+automation+detection)&hl=en-US&gl=US&ceid=US:en' },
  { source: 'courtlistener-linkedin', url: 'https://www.courtlistener.com/feed/search/?q=linkedin&type=r' },
  { source: 'castle-blog', url: 'https://blog.castle.io/rss/' },
  { source: 'fingerprint-blog', url: 'https://fingerprint.com/rss.xml' },
  { source: 'scrapfly-blog', url: 'https://scrapfly.io/blog/feed.xml' }
];
return feeds.map((f) => ({ json: f }));

// Normalizza item RSS → {title, link, guid, date, source}
// source: derivato dall'hostname del link (i nodi RSS non propagano l'input).
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const link = j.link || j.guid || '';
  let host = '';
  try { host = new URL(link).hostname.replace(/^www\./, ''); } catch (e) { host = 'unknown'; }
  out.push({
    json: {
      title: String(j.title || '').slice(0, 300),
      link: String(link).slice(0, 800),
      guid: String(j.guid || j.id || link || j.title || '').slice(0, 500),
      date: j.isoDate || j.pubDate || j.pubdate || '',
      snippet: String(j.contentSnippet || j.content || '').slice(0, 400),
      source: host,
      isError: false
    }
  });
}
return out;

// Fonti JSON/scrape verificate VIVE 2026-06-11.
// HN: query QUOTATA %22linkedin%22 (la typo-tolerance Algolia inquina i risultati senza quote).
const apis = [
  { source: 'hn-linkedin-quoted', url: 'https://hn.algolia.com/api/v1/search_by_date?query=%22linkedin%22&tags=story&numericFilters=points%3E5' },
  { source: 'hn-linkedin-ban', url: 'https://hn.algolia.com/api/v1/search_by_date?query=linkedin%20ban&tags=story&hitsPerPage=20' },
  { source: 'github-openoutreach-issues', url: 'https://api.github.com/repos/eracle/OpenOutreach/issues?state=all&sort=created&direction=desc&per_page=20' },
  { source: 'github-linkedin-mcp-issues', url: 'https://api.github.com/repos/stickerdaniel/linkedin-mcp-server/issues?state=all&sort=created&direction=desc&per_page=20' },
  { source: 'linkedhelper-wp', url: 'https://www.linkedhelper.com/blog/wp-json/wp/v2/posts?per_page=10&orderby=date&_fields=title,link,date' },
  { source: 'linkedin-tos', url: 'https://www.linkedin.com/legal/user-agreement' }
];
return apis.map((a) => ({ json: a }));

// Normalizza risposte API per SHAPE (nessuna dipendenza dal pairing input/output):
// - {hits:[...]} → Hacker News Algolia
// - {html_url, number} → GitHub issue (esclude le PR)
// - {title:{rendered}} → WordPress REST (LinkedHelper)
// - string con 'Effective on <data>' → LinkedIn ToS (guid = data: item nuovo SOLO quando la data cambia)
const out = [];
const push = (o) => out.push({ json: { isError: false, snippet: '', ...o } });
for (const item of $input.all()) {
  const j = item.json;
  if (j && Array.isArray(j.hits)) {
    for (const h of j.hits.slice(0, 20)) {
      push({
        title: String(h.title || h.story_title || '').slice(0, 300),
        link: h.url || ('https://news.ycombinator.com/item?id=' + h.objectID),
        guid: 'hn-' + h.objectID,
        date: h.created_at || '',
        source: 'hackernews'
      });
    }
    continue;
  }
  if (j && j.html_url && typeof j.number !== 'undefined') {
    if (j.pull_request) continue;
    let repo = 'github';
    try { repo = new URL(j.html_url).pathname.split('/').slice(1, 3).join('/'); } catch (e) { /* keep default */ }
    push({
      title: String(j.title || '').slice(0, 300),
      link: j.html_url,
      guid: 'gh-' + repo + '-' + j.number,
      date: j.created_at || '',
      source: 'github:' + repo
    });
    continue;
  }
  if (j && j.title && typeof j.title === 'object' && j.title.rendered) {
    push({
      title: String(j.title.rendered).slice(0, 300),
      link: j.link || '',
      guid: j.link || j.title.rendered,
      date: j.date || '',
      source: 'linkedhelper'
    });
    continue;
  }
  const html = typeof j === 'string' ? j : (typeof j.data === 'string' ? j.data : '');
  if (html && /user.?agreement|effective on/i.test(html)) {
    const m = html.match(/Effective on ([A-Z][a-z]+ \d{1,2}, \d{4})/);
    const effective = m ? m[1] : 'unknown';
    push({
      title: 'LinkedIn User Agreement — Effective on ' + effective,
      link: 'https://www.linkedin.com/legal/user-agreement',
      guid: 'linkedin-tos-' + effective,
      date: effective,
      source: 'linkedin-tos'
    });
  }
}
return out;

// Fonte morta: l'error output dei fetch arriva qui. 1 item/giorno per fonte (guid con data)
// così la fonte rotta resta VISIBILE nel digest senza spammare (fail-visible, non silent).
const day = new Date().toISOString().slice(0, 10);
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const src = (j && (j.source || j.url)) || 'unknown';
  out.push({
    json: {
      title: 'Fonte non raggiungibile: ' + src,
      link: String(j && j.url ? j.url : ''),
      guid: 'fetch-error-' + src + '-' + day,
      date: day,
      snippet: String((j && (j.error && j.error.message ? j.error.message : j.error)) || 'fetch failed').slice(0, 200),
      source: src,
      isError: true
    }
  });
}
return out;

// Filtro keyword PRE-AI: abbatte il rumore misurato (76-87% su alcune fonti) → token AI solo su item plausibili.
// Gli item isError passano sempre (devono arrivare al digest).
const RX = /(detect|ban\b|banned|ban wave|restrict|limit|safe|safety|fingerprint|selector|captcha|checkpoint|lawsuit|litigat|court|scrap|automat|\bbot\b|bots\b|stealth|suspend|flagged|lockout|locked|warning|enforce|crackdown|voyager|challenge|anti-?bot|user agreement|effective on)/i;
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  if (j.isError) { out.push(item); continue; }
  const text = (j.title || '') + ' ' + (j.snippet || '');
  if (RX.test(text)) out.push(item);
}
return out;

// Aggrega gli item NUOVI in un'unica richiesta di classificazione per Claude.
// Vincolo di prodotto (binding detection-news): la sentinella SEGNALA, non modifica parametri.
const items = $input.all().map((i) => i.json);
const content = items.filter((j) => !j.isError).slice(0, 60);
const dead = items.filter((j) => j.isError);
const model = $env.SENTINEL_AI_MODEL || 'claude-sonnet-4-6';
const listing = content.map((j, i) => `${i}. [${j.source}] (${j.date}) ${j.title} — ${j.link}`).join('\n');
const body = {
  model,
  max_tokens: 4000,
  system: 'You are a LinkedIn anti-detection news classifier for a self-hosted LinkedIn outreach bot (Playwright-based, residential proxies). Given news/forum/issue items, identify ONLY those signaling changes in LinkedIn bot-detection, enforcement, ban waves, DOM/selector changes, policy/ToS updates, or relevant legal rulings. Respond with ONLY a JSON array (no prose, no markdown fences), one object per RELEVANT item: {"i": <index>, "severity": "critical"|"high"|"medium"|"low", "impact": ["timing"|"fingerprint"|"proxy"|"volume"|"selectors"|"policy"|"legal"], "summary": "<one line, Italian>"}. severity=critical ONLY for strong evidence of an ACTIVE enforcement change hitting similar tools NOW (e.g. ongoing ban wave, confirmed new detection rollout). Marketing posts, generic tips, old news: omit. Be conservative: when in doubt, lower severity.',
  messages: [{ role: 'user', content: listing || '(no items)' }]
};
return [{ json: {
  hasContent: content.length > 0,
  contentItems: content,
  deadSources: dead,
  aiRequestBody: body
} }];

// Parse risposta AI + clamp severity→action (difesa in profondità sul vincolo:
// pause SOLO per critical; il modello NON può comandare azioni oltre questo mapping).
const prep = $('Prepara analisi').first().json;
const resp = $input.first().json;
let findings = [];
let aiError = '';
try {
  if (resp && resp.error) throw new Error(resp.error.message || 'Anthropic API error');
  let text = resp && resp.content && resp.content[0] ? String(resp.content[0].text || '') : '';
  text = text.replace(/^```(json)?/m, '').replace(/```\s*$/m, '').trim();
  const arr = JSON.parse(text);
  if (!Array.isArray(arr)) throw new Error('AI response is not a JSON array');
  const actionOf = { critical: 'pause', high: 'warn', medium: 'log' };
  findings = arr
    .filter((f) => f && typeof f.i === 'number' && prep.contentItems[f.i])
    .filter((f) => ['critical', 'high', 'medium'].includes(f.severity))
    .map((f) => ({
      severity: f.severity,
      action: actionOf[f.severity],
      impact: Array.isArray(f.impact) ? f.impact.slice(0, 7) : [],
      summary: String(f.summary || '').slice(0, 300),
      title: prep.contentItems[f.i].title,
      url: prep.contentItems[f.i].link,
      source: prep.contentItems[f.i].source,
      date: prep.contentItems[f.i].date
    }));
} catch (e) {
  // Fail-VISIBLE: errore di analisi nel digest, NESSUN POST al bot (niente azioni su dati non analizzati).
  aiError = e.message || String(e);
}
const order = { critical: 0, high: 1, medium: 2 };
findings.sort((a, b) => order[a.severity] - order[b.severity]);
return [{ json: { findings, aiError, analyzedCount: prep.contentItems.length, deadSources: prep.deadSources } }];

// Componi digest WHAT/WHY/DO (L5-LI.1). Arriva o da Parse AI (ramo true) o dall'IF (ramo false).
const j = $input.first().json;
const findings = j.findings || [];
const deadSources = j.deadSources || [];
const aiError = j.aiError || '';
const analyzedCount = typeof j.analyzedCount === 'number' ? j.analyzedCount : 0;
const hasAnything = findings.length > 0 || deadSources.length > 0 || !!aiError;
const icon = { critical: '\uD83D\uDED1', high: '\u26A0\uFE0F', medium: '\u2139\uFE0F' };
let text = '\uD83D\uDEF0 *LinkedIn Detection Sentinel — ' + new Date().toISOString().slice(0, 10) + '*\n';
if (findings.length > 0) {
  text += '\n*WHAT — segnali rilevati (' + findings.length + ' su ' + analyzedCount + ' nuovi item):*\n';
  for (const f of findings.slice(0, 10)) {
    text += icon[f.severity] + ' *' + f.severity.toUpperCase() + '* [' + f.source + '] ' + f.summary + '\n' + f.url + '\n';
  }
  text += '\n*WHY:* fonti monitorate (vendor, community, detection-vendor, legale) segnalano i cambi PRIMA che colpiscano il bot.\n';
  const hasPause = findings.some((f) => f.action === 'pause');
  text += '\n*DO:* ' + (hasPause
    ? 'CRITICAL \u2192 il bot riceve PAUSE difensiva automatica. Verifica subito i link e decidi se prolungare lo stop.'
    : 'verifica i link entro 24h; se confermati, valuta riduzione volumi / aggiornamento selettori.') + '\n';
}
if (aiError) {
  text += '\n\u274C *Analisi AI fallita:* ' + aiError + ' \u2192 nessun alert inviato al bot. Controlla ANTHROPIC_API_KEY / il run n8n.\n';
}
if (deadSources.length > 0) {
  text += '\n\uD83D\uDD0C *Fonti non raggiungibili (' + deadSources.length + '):* ' + deadSources.map((d) => d.source).join(', ') + '\n*DO:* se persiste per giorni, aggiorna la fonte nel workflow.\n';
}
if (!hasAnything) {
  text += '\nNessuna novit\u00E0 rilevante oggi.';
}
return [{ json: { hasAnything, digestText: text, findings } }];

// Un item per finding da inviare al bot (cap 5 anti-flood, ordinati per severity).
// Vincolo: action gi\u00E0 clampata in Parse AI (pause solo critical). digest-only se nessun finding.
const findings = ($input.first().json.findings || []).slice(0, 5);
return findings.map((f) => ({ json: f }));

// Post-hook: logga completamento (pattern repo)
const ts = new Date().toISOString();
const startedAt = $('Pre-hook: valida env').first().json.startedAt;
const durationMs = new Date(ts).getTime() - new Date(startedAt).getTime();
console.log(`[${ts}] linkedin-detection-sentinel completato in ${durationMs}ms`);
return [{ json: { completedAt: ts, durationMs, status: 'ok' } }];
